/* ── Relocation Jobs homepage design system ── */
/* Extends /static/styles.css root vars. Loaded AFTER styles.css. */

/* ── Layout ── */

.max-w-site { max-width: 1080px; }
.section-major { margin-top: 5rem; }
.section-major-first { margin-top: 0; padding-top: 3rem; }
.section-compact { margin-top: 3rem; }

/* ── Surface card ── */

.surface-card {
  border-radius: var(--radius);
  background: var(--surface);
  border: 1px solid var(--border);
}

.surface-card-interactive {
  transition: background var(--duration-normal) var(--ease-out),
              border-color var(--duration-normal) var(--ease-out),
              box-shadow var(--duration-normal) var(--ease-out);
}

.surface-card-interactive:hover {
  background: var(--surface-hover);
  border-color: var(--border-strong);
  box-shadow: var(--shadow-sm);
}

/* ── Header ── */

.shadow-header {
  box-shadow: 0 16px 34px rgba(0, 0, 0, 0.22);
}

/* ── Hero ── */

.hero-enter {
  opacity: 0;
  transform: translateY(12px);
  animation: fadeUp 0.6s var(--ease-out) forwards;
}

.hero-enter-delay-1 { animation-delay: 0.1s; }
.hero-enter-delay-2 { animation-delay: 0.2s; }
.hero-enter-delay-3 { animation-delay: 0.3s; }

@keyframes fadeUp {
  to { opacity: 1; transform: translateY(0); }
}

.text-fluid-hero {
  font-size: clamp(1.75rem, 5.5vw, 3rem);
  font-weight: 700;
  line-height: 1.15;
  letter-spacing: var(--tracking-tight);
}

.text-section-title {
  font-size: clamp(1.25rem, 3.5vw, 1.75rem);
  font-weight: 700;
  line-height: 1.2;
  letter-spacing: var(--tracking-tight);
}

.text-accent-hover { color: var(--accent-hover); }
.text-text { color: var(--text); }
.text-muted { color: var(--muted); }

/* ── Hero search glow ── */

.hero-search-glow {
  position: relative;
  background: var(--surface);
  border: 1px solid var(--border-strong);
  box-shadow:
    0 0 0 1px rgba(56, 189, 248, 0.06),
    0 0 32px rgba(56, 189, 248, 0.04),
    var(--shadow-sm);
}

/* ── Select pill ── */

.select-pill {
  width: 100%;
  padding: 0.625rem 2.25rem 0.625rem 2.5rem;
  border-radius: var(--radius-pill);
  border: 1px solid var(--border);
  background: var(--bg-elevated);
  color: var(--text);
  font-size: var(--text-sm);
  font-family: inherit;
  appearance: none;
  -webkit-appearance: none;
  cursor: pointer;
  transition: border-color var(--duration-fast) var(--ease-out),
              box-shadow var(--duration-fast) var(--ease-out);
}

.select-pill:focus-visible {
  border-color: var(--accent);
  box-shadow: 0 0 0 3px var(--accent-soft);
}

.select-icon { pointer-events: none; position: absolute; }

/* ── Buttons ── */

.btn-primary {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 0.375rem;
  padding: 0.625rem 1.25rem;
  border: none;
  border-radius: var(--radius-pill);
  background: linear-gradient(135deg, var(--accent) 0%, var(--brand-sky) 100%);
  color: #fff;
  font-size: var(--text-sm);
  font-family: inherit;
  font-weight: 600;
  line-height: 1;
  text-decoration: none;
  cursor: pointer;
  transition: opacity var(--duration-fast) var(--ease-out),
              transform var(--duration-fast) var(--ease-out),
              box-shadow var(--duration-fast) var(--ease-out);
}

.btn-primary:hover {
  opacity: 0.9;
  box-shadow: 0 4px 20px rgba(56, 189, 248, 0.25);
}

.btn-primary:active {
  transform: scale(0.97);
}

.btn-outline {
  display: inline-flex;
  align-items: center;
  gap: 0.375rem;
  padding: 0.5rem 1rem;
  border: 1px solid var(--border);
  border-radius: var(--radius-pill);
  background: transparent;
  color: var(--text);
  font-size: var(--text-sm);
  font-family: inherit;
  font-weight: 500;
  text-decoration: none;
  cursor: pointer;
  transition: background var(--duration-fast) var(--ease-out),
              border-color var(--duration-fast) var(--ease-out);
}

.btn-outline:hover {
  background: var(--surface-hover);
  border-color: var(--border-strong);
}

/* ── Pill nav control ── */

.pill-control {
  display: inline-flex;
  align-items: center;
  padding: 0.375rem 0.75rem;
  border-radius: var(--radius-pill);
  color: var(--muted);
  text-decoration: none;
  background: transparent;
  border: none;
  font-family: inherit;
  cursor: pointer;
  transition: background var(--duration-fast) var(--ease-out),
              color var(--duration-fast) var(--ease-out);
}

.pill-control:hover {
  background: rgba(255, 255, 255, 0.06);
  color: var(--text);
}

/* ── Status pills ── */

.pill-status {
  display: inline-flex;
  align-items: center;
  padding: 0.125rem 0.625rem;
  border-radius: var(--radius-pill);
  font-size: var(--text-xs);
  font-weight: 500;
  line-height: 1.5;
  border: 1px solid;
  box-shadow: inset 0 1px 0 rgba(255,255,255,0.08), inset 0 -1px 2px rgba(0,0,0,0.12);
}

.pill-status--looking {
  border-color: rgba(36, 140, 251, 0.28);
  background: linear-gradient(180deg, rgba(36,140,251,0.14) 0%, rgba(36,140,251,0.06) 100%);
  color: #248cfb;
}

.pill-status--applied {
  border-color: rgba(52, 211, 153, 0.22);
  background: linear-gradient(180deg, rgba(52,211,153,0.16) 0%, rgba(52,211,153,0.08) 100%);
  color: #6ee7b7;
}

.pill-status--awaiting {
  border-color: rgba(167, 139, 250, 0.28);
  background: linear-gradient(180deg, rgba(167,139,250,0.18) 0%, rgba(167,139,250,0.08) 100%);
  color: #c4b5fd;
}

.pill-status--visa {
  border-color: rgba(167, 139, 250, 0.22);
  background: linear-gradient(180deg, rgba(167,139,250,0.16) 0%, rgba(167,139,250,0.08) 100%);
  color: #c4b5fd;
}

.pill-status--country {
  border-color: rgba(91, 141, 239, 0.2);
  background: linear-gradient(180deg, rgba(91,141,239,0.18) 0%, rgba(91,141,239,0.08) 100%);
  color: var(--accent-hover);
}

.pill-status--age {
  border-color: rgba(148, 163, 184, 0.2);
  background: linear-gradient(180deg, rgba(148,163,184,0.1) 0%, rgba(148,163,184,0.04) 100%);
  color: #94a3b8;
}

/* ── Alive pill animation ── */

.alive-pill {
  position: relative;
  min-width: 9.5rem;
}

.alive-pill-swap::after {
  content: "Awaiting response";
}

/* ── Reveal card animation ── */

.reveal-card {
  opacity: 0;
  transform: translateY(16px);
  transition: opacity 0.5s var(--ease-out), transform 0.5s var(--ease-out);
}

.reveal-card.is-visible {
  opacity: 1;
  transform: translateY(0);
}

/* ── Brand accent bar ── */

.brand-accent-bar {
  position: absolute;
  pointer-events: none;
  bottom: 0;
  left: 0;
  top: 0;
  width: 0.25rem;
  border-radius: 0 var(--radius) var(--radius) 0;
  background: linear-gradient(180deg, var(--brand-sky) 0%, var(--accent) 52%, var(--visa) 100%);
  opacity: 0.7;
}

/* ponytail: homepage animations use IntersectionObserver for reveal-card;
   swap to CSS scroll-driven animations when browser support is universal. */

/* ── App-sm card border ── */

.rounded-app-sm { border-radius: 10px; }

/* ── Row card ── */

.row-card {
  flex: 1;
  padding: 0.75rem;
  border-radius: var(--radius-sm);
  border: 1px solid rgba(255,255,255,0.06);
  background: rgba(13, 17, 24, 0.8);
  box-shadow: inset 0 1px 0 rgba(255,255,255,0.03);
}

/* ── Footer ── */

.footer-link {
  color: var(--muted);
  text-decoration: none;
  transition: color var(--duration-fast) var(--ease-out);
}

.footer-link:hover { color: var(--text); }

/* ── Responsive ── */

@media (max-width: 640px) {
  .section-major { margin-top: 3rem; }
  .section-major-first { padding-top: 2rem; }
  .section-compact { margin-top: 2rem; }
}

/* ── Visually hidden ── */

.sr-only {
  position: absolute;
  width: 1px;
  height: 1px;
  overflow: hidden;
  clip: rect(0,0,0,0);
  white-space: nowrap;
  border: 0;
}

