/* ── Marketing shell layout ── */
.mkt-shell { min-height: 100vh; }
.mkt-wrap {
  max-width: 1080px;
  margin: 0 auto;
  padding: 1.25rem 1.25rem 2rem;
}
.mkt-header {
  position: relative;
  overflow: visible;
}
.mkt-header-bar {
  position: absolute;
  inset: 0;
  top: 0;
  height: 3px;
  background: var(--brand-gradient);
  pointer-events: none;
}
.mkt-header-row {
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  justify-content: space-between;
  gap: 1rem;
  padding: 1rem 1.25rem;
}
.mkt-brand {
  display: inline-flex;
  align-items: center;
  gap: 0.75rem;
  text-decoration: none;
  color: inherit;
  min-width: 0;
}
.mkt-brand-mark {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 2.65rem;
  height: 2.65rem;
  border-radius: 12px;
  background: #f7f6f3;
  box-shadow: 0 6px 18px rgba(15, 23, 42, 0.18);
  overflow: hidden;
  padding: 0.28rem;
  flex-shrink: 0;
}
.mkt-brand-mark img {
  width: 100%;
  height: 100%;
  object-fit: contain;
  display: block;
}
.mkt-brand-text {
  display: flex;
  flex-direction: column;
  gap: 2px;
  min-width: 0;
}
.mkt-brand-name {
  font-size: 1.125rem;
  font-weight: 600;
  letter-spacing: -0.02em;
  color: var(--text);
}
.mkt-brand-tag {
  font-size: 0.75rem;
  color: var(--muted);
}
.mkt-header-actions {
  display: flex;
  align-items: center;
  gap: 0.5rem;
}
.mkt-nav-list {
  display: flex;
  align-items: center;
  gap: 0.25rem;
  list-style: none;
  margin: 0;
  padding: 0;
}
.mkt-nav-mobile {
  border-top: 1px solid var(--border);
  padding: 0.75rem 1rem;
}
.mkt-nav-mobile ul {
  display: flex;
  flex-wrap: wrap;
  gap: 0.5rem;
  list-style: none;
  margin: 0;
  padding: 0;
}
.mkt-avatar {
  display: flex;
  align-items: center;
  justify-content: center;
  width: 2rem;
  height: 2rem;
  border-radius: 50%;
  background: linear-gradient(135deg, var(--accent), #6b5ce7);
  font-size: 0.75rem;
  font-weight: 700;
  color: #fff;
  text-decoration: none;
  box-shadow: 0 0 0 2px #080a0f, 0 0 0 3px rgba(255, 255, 255, 0.1);
}
.mkt-main-narrow {
  margin: 0 auto;
  margin-top: 3rem;
  max-width: 42rem;
}
.mkt-footer {
  border-top: 1px solid var(--border);
  padding: 2rem 0;
  margin-top: 3rem;
}
.mkt-footer-inner {
  display: flex;
  flex-direction: column;
  gap: 1rem;
}
.mkt-footer-nav ul {
  display: flex;
  flex-wrap: wrap;
  gap: 0.5rem;
  list-style: none;
  margin: 0;
  padding: 0;
}
.mkt-step-list {
  margin-top: 2.5rem;
  display: flex;
  flex-direction: column;
  gap: 1.25rem;
}
.mkt-step-card {
  padding: 1.5rem 1.25rem;
}
.mkt-pricing-grid {
  margin-top: 2.5rem;
  display: grid;
  gap: 1.25rem;
}
.mkt-feature-list {
  margin-top: 1rem;
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
  list-style: none;
  padding: 0;
  font-size: var(--text-sm);
  color: var(--muted);
}
.mkt-cta-center {
  margin-top: 2.5rem;
  text-align: center;
}
.nav-desktop { display: none; }

@media (min-width: 640px) {
  .nav-desktop { display: flex !important; }
  .nav-mobile,
  .mkt-nav-mobile { display: none !important; }
  .mkt-footer-inner {
    flex-direction: row;
    align-items: center;
    justify-content: space-between;
  }
