    sel.value = pick;
    if (fromUrl) localStorage.setItem("panel_country", fromUrl);
  } else {
    const first = countries.find((c) => c.id !== "all");
    if (first) sel.value = first.id;
  }
  const q = params.get("q");
  const search = $("search");
  if (q && search) search.value = q;
}

